INSERT INTO agents.health_knowledge (content, embedding, metadata) VALUES
  ('The 2023 Australian CVD Risk Guideline (Heart Foundation/RACGP) uses the AusCVD Risk Calculator to estimate 5-year absolute cardiovascular disease risk. Low risk is defined as < 5%, intermediate as 5–< 10%, and high risk as ≥ 10%. People at high risk should initiate both blood pressure–lowering and lipid-modifying pharmacotherapy. Reassessment is recommended within 2 years for intermediate-risk patients and within 5 years for low-risk patients.', '[0,0.1171875,0.25,-0.0859375,0,-0.0703125,0.1015625,0.5,0.0234375,-0.9765625,0.203125,-0.2734375,-0.1328125,-0.3984375,-0.0390625,-0.4140625,-0.015625,0.0234375,-0.2109375,-0.0078125,-0.015625,-0.171875,-0.25,-0.3828125,-0.8359375,0.0703125,-0.078125,0.4453125,-0.140625,0.2265625,-0.6015625,0.03125,0.53125,-0.03125,-0.109375,0.328125,-0.4296875,-0.03125,-0.2421875,0.265625,-0.0234375,0.21875,-0.1796875,0.1328125,-0.2421875,-0.03125,0,-0.140625,0.2890625,0.0078125,0.09375,-0.0625,0.09375,0.125,0.4140625,-0.2734375,0.1640625,-0.046875,0.5234375,-0.6328125,0,0.1953125,0.2734375,0.15625,0.1015625,0.3203125,-0.0859375,-0.6796875,0.09375,0.109375,-0.3984375,0.28125,-0.390625,0.1953125,0.0078125,0.28125,-0.25,-0.0234375,-0.6953125,0.4296875,-0.390625,-0.4296875,-0.1171875,0.7890625,0.140625,0.2734375,0.3046875,0.3046875,-0.1328125,-0.3359375,-0.140625,0,-0.1953125,-0.234375,0.0859375,-0.0234375,-0.3125,-0.5234375,0.3515625,-0.484375,-0.2734375,-0.296875,-0.0625,-0.09375,0.46875,-0.28125,-0.03125,-0.25,-0.2578125,0.09375,-0.3828125,-0.21875,-0.328125,-0.25,0.3828125,0.140625,0.3828125,0.015625,-0.3203125,-0.265625,-0.203125,0.078125,-0.171875,-0.0703125,-0.546875,0.0078125,0.1796875,0.359375,-0.0625,-0.03125,-0.8046875,0.2421875,0.28125,0.046875,-0.4921875,-0.078125,-0.3359375,0.1953125,-0.296875,0.109375,0.0078125,-0.09375,-0.1015625,0.2265625,0.1328125,-0.296875,0.0703125,-0.125,0.140625,-0.125,-0.0625,0.1796875,-0.2265625,0.2109375,0.0546875,0.171875,0.15625,0.2109375,-0.1171875,-0.140625,0.1796875,-0.109375,-0.6640625,-0.2